sys_script_include.script:
var SearchPulseClassifier = Class.create();

SearchPulseClassifier.prototype = {

    type: 'SearchPulseClassifier',

    classifySession: function(sessionRecord) {
        if (!sessionRecord || !sessionRecord.isValidRecord()) {
            gs.logWarning('SearchPulseClassifier: invalid sessionRecord supplied', 'SearchPulse');
            return 'ambiguous';
        }

        var outcome = this._determineOutcome(sessionRecord);

        this._writeOutcomeRecord(sessionRecord, outcome);
        this._markSessionClassified(sessionRecord);

        gs.log(
            'SearchPulseClassifier: session ' + sessionRecord.getValue('session_id') +
            ' classified as ' + outcome,
            'SearchPulse'
        );

        return outcome;
    },

    _determineOutcome: function(s) {
        var summaryFeedback = s.getValue('summary_feedback');
        var scrolled        = s.getValue('scrolled_to_results') === '1' || s.scrolled_to_results == true;
        var clickedArticle  = s.getValue('clicked_article');
        var cameBack        = s.getValue('came_back_to_search') === '1' || s.came_back_to_search == true;
        var reformulated    = s.getValue('reformulated_query') === '1' || s.reformulated_query == true;

        var hasClick = clickedArticle && clickedArticle !== '';

        if (summaryFeedback === 'up' && !scrolled && !hasClick) {
            return 'summary_satisfied';
        }
        if (scrolled && hasClick && !cameBack) {
            return 'drilled_down';
        }
        if (hasClick && cameBack) {
            return 'result_failed';
        }
        if (reformulated) {
            return 'full_failure';
        }
        if (summaryFeedback === 'down') {
            return 'summary_rejected';
        }
        return 'ambiguous';
    },

    _writeOutcomeRecord: function(sessionRecord, outcome) {
        var outcomeGR = new GlideRecord('u_sp_search_outcome');
        outcomeGR.initialize();
        outcomeGR.setValue('session',            sessionRecord.getUniqueValue());
        outcomeGR.setValue('outcome_type',       outcome);
        outcomeGR.setValue('created',            new GlideDateTime().getDisplayValue());
        outcomeGR.setValue('reputation_applied', false);

        var clickedArticle = sessionRecord.getValue('clicked_article');
        if (clickedArticle && clickedArticle !== '') {
            outcomeGR.setValue('impacted_article', clickedArticle);
        }
        outcomeGR.insert();
    },

    _markSessionClassified: function(sessionRecord) {
        sessionRecord.setValue('outcome_classified', true);
        sessionRecord.update();
    },

    classifyPendingSessions: function() {
        var count = 0;
        var gr = new GlideRecord('u_sp_search_session');
        gr.addQuery('outcome_classified', false);

        var cutoff = new GlideDateTime();
        cutoff.addSeconds(-1800);
        gr.addQuery('created', '<=', cutoff.getValue());
        gr.query();

        while (gr.next()) {
            this.classifySession(gr);
            count++;
        }

        gs.log('SearchPulseClassifier: bulk classified ' + count + ' pending sessions', 'SearchPulse');
        return count;
    }
};

var SearchPulseRankingEngine = Class.create();

SearchPulseRankingEngine.prototype = {

    type: 'SearchPulseRankingEngine',

    getReputationMultiplier: function(articleSysId) {
        var score = this._getReputationScore(articleSysId);
        return this._multiplierFromScore(score);
    },

    getFinalScore: function(articleSysId, baseScore) {
        var multiplier = this.getReputationMultiplier(articleSysId);
        var finalScore = baseScore * multiplier;
        gs.debug(
            'SearchPulseRankingEngine: article=' + articleSysId +
            ' base=' + baseScore + ' multiplier=' + multiplier + ' final=' + finalScore,
            'SearchPulse'
        );
        return finalScore;
    },

    reRankResults: function(results) {
        if (!results || results.length === 0) { return results; }

        for (var i = 0; i < results.length; i++) {
            var result = results[i];
            if (result.sys_id) {
                result.original_score = result.score;
                result.score          = this.getFinalScore(result.sys_id, result.score || 1.0);
                result.multiplier     = this.getReputationMultiplier(result.sys_id);
            }
        }

        results.sort(function(a, b) { return b.score - a.score; });
        return results;
    },

    getArticleReputationInfo: function(articleSysId) {
        var score = this._getReputationScore(articleSysId);
        return {
            score:             score,
            multiplier:        this._multiplierFromScore(score),
            positive_sessions: this._getField(articleSysId, 'positive_sessions', 0),
            negative_sessions: this._getField(articleSysId, 'negative_sessions', 0),
            total_sessions:    this._getField(articleSysId, 'total_sessions', 0),
            score_trend:       this._getField(articleSysId, 'score_trend', 'stable')
        };
    },

    _getReputationScore: function(articleSysId) {
        if (!articleSysId) { return 50; }
        var gr = new GlideRecord('u_sp_article_reputation');
        gr.addQuery('article', articleSysId);
        gr.setLimit(1);
        gr.query();
        return gr.next() ? (parseInt(gr.getValue('reputation_score'), 10) || 50) : 50;
    },

    _getField: function(articleSysId, fieldName, defaultVal) {
        var gr = new GlideRecord('u_sp_article_reputation');
        gr.addQuery('article', articleSysId);
        gr.setLimit(1);
        gr.query();
        if (gr.next()) {
            var val = gr.getValue(fieldName);
            return val !== null ? val : defaultVal;
        }
        return defaultVal;
    },

    _multiplierFromScore: function(score) {
        if (score >= 75) { return 1.2; }
        if (score >= 50) { return 1.0; }
        if (score >= 30) { return 0.8; }
        return 0.5;
    }
};

var SearchPulseBadgeService = Class.create();

SearchPulseBadgeService.prototype = {

    type: 'SearchPulseBadgeService',

    BADGE_FREQUENTLY_HELPFUL: 'frequently_helpful',
    BADGE_UPDATED_RECENTLY:   'updated_recently',
    BADGE_MAY_BE_OUTDATED:    'may_be_outdated',
    BADGE_NONE:               'none',

    getBadge: function(articleSysId) {
        if (!articleSysId) { return this._noBadge(); }

        var repScore        = this._getReputationScore(articleSysId);
        var articleAge      = this._getArticleAgeInDays(articleSysId);
        var daysSinceUpdate = this._getDaysSinceUpdate(articleSysId);

        if (repScore >= 75) {
            return this._badge(this.BADGE_FREQUENTLY_HELPFUL, 'Frequently Helpful', 'green', 'check-circle');
        }
        if (daysSinceUpdate !== null && daysSinceUpdate <= 30 && repScore >= 50) {
            return this._badge(this.BADGE_UPDATED_RECENTLY, 'Updated Recently', 'blue', 'refresh');
        }
        if (repScore >= 30 && repScore <= 49 && articleAge !== null && articleAge > 180) {
            return this._badge(this.BADGE_MAY_BE_OUTDATED, 'May Be Outdated', 'amber', 'alert-triangle');
        }
        return this._noBadge();
    },

    getBadgesForArticles: function(articleSysIds) {
        if (!articleSysIds || articleSysIds.length === 0) { return {}; }

        var repMap     = this._bulkFetchReputation(articleSysIds);
        var articleMeta = this._bulkFetchArticleMeta(articleSysIds);
        var result     = {};

        for (var i = 0; i < articleSysIds.length; i++) {
            var sysId           = articleSysIds[i];
            var repScore        = repMap[sysId]      ? repMap[sysId].score        : 50;
            var articleAge      = articleMeta[sysId] ? articleMeta[sysId].age     : null;
            var daysSinceUpdate = articleMeta[sysId] ? articleMeta[sysId].updated : null;

            if (repScore >= 75) {
                result[sysId] = this._badge(this.BADGE_FREQUENTLY_HELPFUL, 'Frequently Helpful', 'green', 'check-circle');
            } else if (daysSinceUpdate !== null && daysSinceUpdate <= 30 && repScore >= 50) {
                result[sysId] = this._badge(this.BADGE_UPDATED_RECENTLY, 'Updated Recently', 'blue', 'refresh');
            } else if (repScore >= 30 && repScore <= 49 && articleAge !== null && articleAge > 180) {
                result[sysId] = this._badge(this.BADGE_MAY_BE_OUTDATED, 'May Be Outdated', 'amber', 'alert-triangle');
            } else {
                result[sysId] = this._noBadge();
            }
        }
        return result;
    },

    _getReputationScore: function(articleSysId) {
        var gr = new GlideRecord('u_sp_article_reputation');
        gr.addQuery('article', articleSysId);
        gr.setLimit(1);
        gr.query();
        return gr.next() ? (parseInt(gr.getValue('reputation_score'), 10) || 50) : 50;
    },

    _getArticleAgeInDays: function(articleSysId) {
        var gr = new GlideRecord('kb_knowledge');
        if (!gr.get(articleSysId)) { return null; }
        var created = gr.getValue('sys_created_on');
        if (!created) { return null; }
        var createdGDT = new GlideDateTime(created);
        var now        = new GlideDateTime();
        var diff       = GlideDateTime.subtract(createdGDT, now);
        return Math.abs(Math.floor(diff.getDayPart()));
    },

    _getDaysSinceUpdate: function(articleSysId) {
        var gr = new GlideRecord('kb_knowledge');
        if (!gr.get(articleSysId)) { return null; }
        var updated = gr.getValue('sys_updated_on');
        if (!updated) { return null; }
        var updatedGDT = new GlideDateTime(updated);
        var now        = new GlideDateTime();
        var diff       = GlideDateTime.subtract(updatedGDT, now);
        return Math.abs(Math.floor(diff.getDayPart()));
    },

    _bulkFetchReputation: function(sysIds) {
        var map = {};
        var gr  = new GlideRecord('u_sp_article_reputation');
        gr.addQuery('article', 'IN', sysIds.join(','));
        gr.query();
        while (gr.next()) {
            map[gr.getValue('article')] = { score: parseInt(gr.getValue('reputation_score'), 10) || 50 };
        }
        return map;
    },

    _bulkFetchArticleMeta: function(sysIds) {
        var map = {};
        var now = new GlideDateTime();
        var gr  = new GlideRecord('kb_knowledge');
        gr.addQuery('sys_id', 'IN', sysIds.join(','));
        gr.query();
        while (gr.next()) {
            var sid             = gr.getUniqueValue();
            var created         = gr.getValue('sys_created_on');
            var updated         = gr.getValue('sys_updated_on');
            var ageInDays       = null;
            var daysSinceUpdate = null;
            if (created) {
                var diffC = GlideDateTime.subtract(new GlideDateTime(created), now);
                ageInDays = Math.abs(Math.floor(diffC.getDayPart()));
            }
            if (updated) {
                var diffU = GlideDateTime.subtract(new GlideDateTime(updated), now);
                daysSinceUpdate = Math.abs(Math.floor(diffU.getDayPart()));
            }
            map[sid] = { age: ageInDays, updated: daysSinceUpdate };
        }
        return map;
    },

    _badge: function(type, label, color, icon) {
        return { type: type, label: label, color: color, icon: icon, show: true };
    },

    _noBadge: function() {
        return { type: this.BADGE_NONE, label: '', color: null, icon: null, show: false };
    }
};

sys_trigger.script:
gs.log('SearchPulseReputationJob: starting nightly run', 'SearchPulse');

var jobStartTime   = new GlideDateTime();
var totalProcessed = 0;
var totalUpdated   = 0;

try {
    _classifyPendingSessions();

    var articleSysIds = _getArticlesWithNewOutcomes();

    gs.log('SearchPulseReputationJob: ' + articleSysIds.length + ' articles to score', 'SearchPulse');

    for (var i = 0; i < articleSysIds.length; i++) {
        var articleId = articleSysIds[i];
        try {
            var updated = _recalculateReputation(articleId);
            totalProcessed++;
            if (updated) { totalUpdated++; }
        } catch(articleErr) {
            gs.logError('SearchPulseReputationJob: error processing article=' + articleId + ' err=' + articleErr.message, 'SearchPulse');
        }
    }

    _markOutcomesApplied(articleSysIds);

    var elapsed = GlideDateTime.subtract(jobStartTime, new GlideDateTime()).getNumericValue() / 1000;
    gs.log('SearchPulseReputationJob: completed. processed=' + totalProcessed + ' updated=' + totalUpdated + ' elapsed=' + elapsed + 's', 'SearchPulse');

} catch (e) {
    gs.logError('SearchPulseReputationJob: fatal error - ' + e.message, 'SearchPulse');
}

function _classifyPendingSessions() {
    var classifier = new x_sp_searchpulse.SearchPulseClassifier();
    var count = classifier.classifyPendingSessions();
    gs.log('SearchPulseReputationJob: pre-classified ' + count + ' orphaned sessions', 'SearchPulse');
}

function _getArticlesWithNewOutcomes() {
    var sysIds = [];
    var seen   = {};
    var gr = new GlideRecord('u_sp_search_outcome');
    gr.addQuery('reputation_applied', false);
    gr.addNotNullQuery('impacted_article');
    gr.query();
    while (gr.next()) {
        var artId = gr.getValue('impacted_article');
        if (artId && !seen[artId]) { seen[artId] = true; sysIds.push(artId); }
    }
    return sysIds;
}

function _recalculateReputation(articleSysId) {
    var outcomes = _getOutcomesForArticle(articleSysId);
    if (outcomes.length === 0) { return false; }

    var positiveDelta = 0, negativeDelta = 0, posCount = 0, negCount = 0;
    var POSITIVE_WEIGHT = { 'summary_satisfied': 3, 'drilled_down': 2 };
    var NEGATIVE_WEIGHT = { 'summary_rejected': 3, 'result_failed': 2, 'full_failure': 1 };

    for (var i = 0; i < outcomes.length; i++) {
        var ot = outcomes[i];
        if (POSITIVE_WEIGHT[ot])      { positiveDelta += POSITIVE_WEIGHT[ot]; posCount++; }
        else if (NEGATIVE_WEIGHT[ot]) { negativeDelta += NEGATIVE_WEIGHT[ot]; negCount++; }
    }

    var repGR = new GlideRecord('u_sp_article_reputation');
    var isNew = false;
    repGR.addQuery('article', articleSysId);
    repGR.setLimit(1);
    repGR.query();

    if (!repGR.next()) {
        repGR = new GlideRecord('u_sp_article_reputation');
        repGR.initialize();
        repGR.setValue('article', articleSysId);
        repGR.setValue('reputation_score', 50);
        repGR.setValue('positive_sessions', 0);
        repGR.setValue('negative_sessions', 0);
        repGR.setValue('total_sessions', 0);
        isNew = true;
    }

    var currentScore  = parseInt(repGR.getValue('reputation_score'), 10) || 50;
    var previousScore = currentScore;
    var newScore      = Math.min(100, Math.max(0, currentScore + (positiveDelta - negativeDelta)));
    var newPositive   = (parseInt(repGR.getValue('positive_sessions'), 10) || 0) + posCount;
    var newNegative   = (parseInt(repGR.getValue('negative_sessions'), 10) || 0) + negCount;
    var newTotal      = (parseInt(repGR.getValue('total_sessions'), 10)    || 0) + outcomes.length;
    var successRate   = newTotal > 0 ? parseFloat(((newPositive / newTotal) * 100).toFixed(2)) : 0.0;
    var trend         = newScore > previousScore + 2 ? 'rising' : newScore < previousScore - 2 ? 'falling' : 'stable';

    repGR.setValue('previous_score',           previousScore);
    repGR.setValue('reputation_score',         newScore);
    repGR.setValue('positive_sessions',        newPositive);
    repGR.setValue('negative_sessions',        newNegative);
    repGR.setValue('total_sessions',           newTotal);
    repGR.setValue('last_calculated',          new GlideDateTime().getValue());
    repGR.setValue('score_trend',              trend);
    repGR.setValue('first_click_success_rate', successRate);

    if (isNew) { repGR.insert(); } else { repGR.update(); }
    return true;
}

function _getOutcomesForArticle(articleSysId) {
    var types = [];
    var gr    = new GlideRecord('u_sp_search_outcome');
    gr.addQuery('impacted_article', articleSysId);
    gr.addQuery('reputation_applied', false);
    gr.query();
    while (gr.next()) { types.push(gr.getValue('outcome_type')); }
    return types;
}

function _markOutcomesApplied(articleSysIds) {
    if (!articleSysIds || articleSysIds.length === 0) { return; }
    var gr = new GlideRecord('u_sp_search_outcome');
    gr.addQuery('impacted_article', 'IN', articleSysIds.join(','));
    gr.addQuery('reputation_applied', false);
    gr.query();
    var count = 0;
    while (gr.next()) { gr.setValue('reputation_applied', true); gr.update(); count++; }
    gs.log('SearchPulseReputationJob: marked ' + count + ' outcomes as applied', 'SearchPulse');
}

sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    var body = request.body.data;

    if (!body || !body.query) {
        response.setStatus(400);
        response.setBody({ error: 'Missing required field: query' });
        return;
    }

    var query     = body.query;
    var userSysId = body.user_sys_id || null;
    var sessionId = body.session_id  || gs.generateGUID().replace(/-/g, '').substring(0, 32);

    var existing = new GlideRecord('u_sp_search_session');
    existing.addQuery('session_id', sessionId);
    existing.setLimit(1);
    existing.query();

    if (existing.next()) {
        response.setStatus(200);
        response.setBody({ session_id: sessionId, status: 'already_exists' });
        return;
    }

    var gr = new GlideRecord('u_sp_search_session');
    gr.initialize();
    gr.setValue('session_id',           sessionId);
    gr.setValue('query',                query);
    gr.setValue('scrolled_to_results',  false);
    gr.setValue('came_back_to_search',  false);
    gr.setValue('reformulated_query',   false);
    gr.setValue('summary_feedback',     'none');
    gr.setValue('outcome_classified',   false);
    gr.setValue('session_duration_seconds', 0);
    gr.setValue('created',              new GlideDateTime().getValue());

    if (userSysId) {
        var userGR = new GlideRecord('sys_user');
        if (userGR.get(userSysId)) { gr.setValue('user', userSysId); }
    }

    var newSysId = gr.insert();

    if (!newSysId) {
        response.setStatus(500);
        response.setBody({ error: 'Failed to create session' });
        return;
    }

    gs.log('SearchPulse: Session started id=' + sessionId + ' query=' + query, 'SearchPulse');
    response.setStatus(201);
    response.setBody({ session_id: sessionId, sys_id: newSysId, status: 'created' });

})(request, response);

(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    var body = request.body.data;

    if (!body || !body.session_id || !body.signal_type) {
        response.setStatus(400);
        response.setBody({ error: 'Missing required fields: session_id, signal_type' });
        return;
    }

    var sessionId  = body.session_id;
    var signalType = body.signal_type;
    var articleId  = body.article || null;

    var validSignals = ['summary_thumbs_up','summary_thumbs_down','scroll_to_results','result_click','return_to_search','query_reformulation'];

    if (validSignals.indexOf(signalType) === -1) {
        response.setStatus(400);
        response.setBody({ error: 'Invalid signal_type. Allowed: ' + validSignals.join(', ') });
        return;
    }

    var gr = new GlideRecord('u_sp_search_session');
    gr.addQuery('session_id', sessionId);
    gr.setLimit(1);
    gr.query();

    if (!gr.next()) {
        response.setStatus(404);
        response.setBody({ error: 'Session not found: ' + sessionId });
        return;
    }

    var updated = false;

    switch (signalType) {
        case 'summary_thumbs_up':
            if (gr.getValue('summary_feedback') === 'none') { gr.setValue('summary_feedback', 'up'); updated = true; }
            break;
        case 'summary_thumbs_down':
            if (gr.getValue('summary_feedback') === 'none') { gr.setValue('summary_feedback', 'down'); updated = true; }
            break;
        case 'scroll_to_results':
            if (gr.getValue('scrolled_to_results') !== '1') { gr.setValue('scrolled_to_results', true); updated = true; }
            break;
        case 'result_click':
            if (!gr.getValue('clicked_article') && articleId) {
                var articleGR = new GlideRecord('kb_knowledge');
                if (articleGR.get(articleId)) { gr.setValue('clicked_article', articleId); updated = true; }
            }
            break;
        case 'return_to_search':
            if (gr.getValue('came_back_to_search') !== '1') { gr.setValue('came_back_to_search', true); updated = true; }
            break;
        case 'query_reformulation':
            if (gr.getValue('reformulated_query') !== '1') { gr.setValue('reformulated_query', true); updated = true; }
            break;
    }

    if (updated) { gr.update(); }

    response.setStatus(200);
    response.setBody({ session_id: sessionId, signal_type: signalType, status: updated ? 'recorded' : 'no_change' });

})(request, response);

(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    var body = request.body.data;

    if (!body || !body.session_id) {
        response.setStatus(400);
        response.setBody({ error: 'Missing required field: session_id' });
        return;
    }

    var sessionId       = body.session_id;
    var durationSeconds = body.duration_seconds || 0;

    var gr = new GlideRecord('u_sp_search_session');
    gr.addQuery('session_id', sessionId);
    gr.setLimit(1);
    gr.query();

    if (!gr.next()) {
        response.setStatus(404);
        response.setBody({ error: 'Session not found: ' + sessionId });
        return;
    }

    if (gr.getValue('outcome_classified') === '1') {
        var existingOutcome = _getExistingOutcome(gr.getUniqueValue());
        response.setStatus(200);
        response.setBody({ session_id: sessionId, outcome: existingOutcome, status: 'already_classified' });
        return;
    }

    if (durationSeconds > 0) {
        gr.setValue('session_duration_seconds', durationSeconds);
        gr.update();
    }

    var classifier = new x_sp_searchpulse.SearchPulseClassifier();
    var outcome    = classifier.classifySession(gr);

    gs.log('SearchPulse: session=' + sessionId + ' ended, outcome=' + outcome, 'SearchPulse');

    response.setStatus(200);
    response.setBody({ session_id: sessionId, outcome: outcome, status: 'classified' });

    function _getExistingOutcome(sessionSysId) {
        var outcomeGR = new GlideRecord('u_sp_search_outcome');
        outcomeGR.addQuery('session', sessionSysId);
        outcomeGR.orderByDesc('created');
        outcomeGR.setLimit(1);
        outcomeGR.query();
        return outcomeGR.next() ? outcomeGR.getValue('outcome_type') : 'unknown';
    }

})(request, response);

sp_widget.client_script:
function SearchPulseWidgetCtrl($scope, $rootScope, $timeout, $sce, spUtil) {
    'use strict';

    var c = this;

    c.searchQuery     = '';
    c.lastQuery       = '';
    c.results         = [];
    c.aiSummary       = null;
    c.loading         = false;
    c.searched        = false;
    c.error           = false;
    c.summaryFeedback = null;
    c.debugMode       = false;

    var sessionId      = null;
    var sessionStarted = false;
    var scrollTracked  = false;
    var sessionStartMs = null;
    var API_BASE       = '/api/x_sp_searchpulse';

    c.$onInit = function() {
        var returnFlag = sessionStorage.getItem('sp_searchpulse_return');
        if (returnFlag) {
            var prevSessionId = sessionStorage.getItem('sp_searchpulse_session_id');
            if (prevSessionId) { sessionId = prevSessionId; _sendSignal('return_to_search', null); }
            sessionStorage.removeItem('sp_searchpulse_return');
        }
        _attachScrollListener();
    };

    c.submitSearch = function() {
        var query = (c.searchQuery || '').trim();
        if (!query || query.length < 2) { return; }

        var isReformulation = sessionStarted && query !== c.lastQuery;
        if (isReformulation) { _sendSignal('query_reformulation', null); }

        c.lastQuery       = query;
        c.loading         = true;
        c.error           = false;
        c.searched        = true;
        c.results         = [];
        c.aiSummary       = null;
        c.summaryFeedback = null;
        scrollTracked     = false;

        _startSession(query, isReformulation);

        $scope.server.update().then(function(resp) {
            c.loading = false;
            if (resp.data.results) {
                c.results   = resp.data.results;
                c.aiSummary = resp.data.aiSummary ? $sce.trustAsHtml(resp.data.aiSummary) : null;
            }
        }, function() { c.loading = false; c.error = true; });
    };

    c.onQueryKeyUp = function($event) {
        if ($event.keyCode === 13) { c.submitSearch(); }
    };

    c.onResultClick = function(result) {
        if (!result || !result.sys_id) { return; }
        _sendSignal('result_click', result.sys_id);
        sessionStorage.setItem('sp_searchpulse_return',     '1');
        sessionStorage.setItem('sp_searchpulse_session_id', sessionId || '');
    };

    c.sendSummaryFeedback = function(vote) {
        if (c.summaryFeedback !== null) { return; }
        c.summaryFeedback = vote;
        _sendSignal(vote === 'up' ? 'summary_thumbs_up' : 'summary_thumbs_down', null);
    };

    c.getBadgeIconClass = function(iconName) {
        var iconMap = { 'check-circle': 'fa-check-circle', 'refresh': 'fa-refresh', 'alert-triangle': 'fa-exclamation-triangle' };
        return iconMap[iconName] || 'fa-tag';
    };

    function _startSession(query, isReformulation) {
        if (!isReformulation) {
            sessionId      = _generateSessionId();
            sessionStarted = true;
            sessionStartMs = Date.now();
            _beacon(API_BASE + '/session/start', JSON.stringify({
                session_id:  sessionId,
                query:       query,
                user_sys_id: window.NOW && NOW.user ? NOW.user.sys_id : null
            }));
            window.addEventListener('beforeunload', _endSession);
        }
    }

    function _endSession() {
        if (!sessionId) { return; }
        var durationSeconds = sessionStartMs ? Math.floor((Date.now() - sessionStartMs) / 1000) : 0;
        _beacon(API_BASE + '/session/end', JSON.stringify({ session_id: sessionId, duration_seconds: durationSeconds }));
        sessionId = null; sessionStarted = false;
    }

    function _sendSignal(signalType, articleSysId) {
        if (!sessionId) { return; }
        var payload = { session_id: sessionId, signal_type: signalType };
        if (articleSysId) { payload.article = articleSysId; }
        _beacon(API_BASE + '/session/signal', JSON.stringify(payload));
    }

    function _attachScrollListener() {
        var resultsSection = null;
        function _onScroll() {
            if (scrollTracked || !sessionId) { return; }
            if (!resultsSection) { resultsSection = document.getElementById('sp-results-section'); }
            if (!resultsSection) { return; }
            var rect = resultsSection.getBoundingClientRect();
            if (rect.top < window.innerHeight) {
                scrollTracked = true;
                _sendSignal('scroll_to_results', null);
                window.removeEventListener('scroll', _onScroll);
            }
        }
        window.addEventListener('scroll', _onScroll, { passive: true });
    }

    function _beacon(url, jsonPayload) {
        try {
            var blob = new Blob([jsonPayload], { type: 'application/json' });
            if (!navigator.sendBeacon(url, blob)) { _xhrFallback(url, jsonPayload); }
        } catch (e) { _xhrFallback(url, jsonPayload); }
    }

    function _xhrFallback(url, jsonPayload) {
        try {
            var xhr = new XMLHttpRequest();
            xhr.open('POST', url, true);
            xhr.setRequestHeader('Content-Type', 'application/json');
            xhr.setRequestHeader('X-UserToken', window.g_ck || '');
            xhr.send(jsonPayload);
        } catch (e) {}
    }

    function _generateSessionId() {
        var arr = new Uint8Array(16);
        if (window.crypto && window.crypto.getRandomValues) { window.crypto.getRandomValues(arr); }
        else { for (var i = 0; i < 16; i++) { arr[i] = Math.floor(Math.random() * 256); } }
        return Array.from(arr).map(function(b) { return ('00' + b.toString(16)).slice(-2); }).join('');
    }
}

sp_widget.script:
(function() {
    'use strict';

    var query      = input && input.searchQuery ? input.searchQuery.trim() : '';
    var maxResults = (options && options.max_results) ? parseInt(options.max_results, 10) : 10;
    var kbCategory = (options && options.kb_category) ? options.kb_category : null;

    data.results   = [];
    data.aiSummary = null;

    if (!query || query.length < 2) { return; }

    try {
        var rawResults = _searchKnowledge(query, maxResults, kbCategory);
        if (!rawResults || rawResults.length === 0) { data.results = []; return; }

        var rankingEngine = new x_sp_searchpulse.SearchPulseRankingEngine();
        var reRanked      = rankingEngine.reRankResults(rawResults);

        var sysIds       = reRanked.map(function(r) { return r.sys_id; });
        var badgeService = new x_sp_searchpulse.SearchPulseBadgeService();
        var badgeMap     = badgeService.getBadgesForArticles(sysIds);

        for (var i = 0; i < reRanked.length; i++) {
            reRanked[i].badge = badgeMap[reRanked[i].sys_id] || { show: false };
        }

        data.results   = reRanked;
        data.aiSummary = _generateAISummaryStub(query, reRanked);

    } catch (e) {
        gs.logError('SearchPulse widget server error: ' + e.message, 'SearchPulse');
        data.results = [];
        data.error   = true;
    }

    function _searchKnowledge(q, limit, categoryId) {
        var results = [];
        var gr      = new GlideRecord('kb_knowledge');
        gr.addActiveQuery();
        gr.addQuery('workflow_state', 'published');
        if (categoryId) { gr.addQuery('kb_category', categoryId); }
        var qc = gr.addQuery('short_description', 'CONTAINS', q);
        qc.addOrCondition('text', 'CONTAINS', q);
        gr.setLimit(limit * 2);
        gr.orderByDesc('sys_updated_on');
        gr.query();

        var baseScore = limit * 2;
        while (gr.next()) {
            var titleMatch = (gr.getValue('short_description') || '').toLowerCase().indexOf(q.toLowerCase()) !== -1;
            var score      = titleMatch ? baseScore * 1.5 : baseScore;
            baseScore--;
            results.push({
                sys_id:         gr.getUniqueValue(),
                title:          gr.getDisplayValue('short_description'),
                snippet:        _buildSnippet(gr.getValue('text'), q),
                url:            '/kb_view.do?sysparm_article=' + gr.getValue('number'),
                category:       gr.getDisplayValue('kb_category'),
                updated:        _relativeDate(gr.getValue('sys_updated_on')),
                score:          score,
                original_score: score,
                multiplier:     1.0
            });
        }
        return results;
    }

    function _buildSnippet(fullText, q) {
        if (!fullText) { return ''; }
        var plain = fullText.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
        var idx   = plain.toLowerCase().indexOf(q.toLowerCase());
        if (idx === -1) { return plain.substring(0, 160) + (plain.length > 160 ? '...' : ''); }
        var start   = Math.max(0, idx - 60);
        var end     = Math.min(plain.length, idx + q.length + 100);
        var snippet = (start > 0 ? '...' : '') + plain.substring(start, end) + (end < plain.length ? '...' : '');
        return snippet.replace(new RegExp('(' + q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ')', 'gi'), '<strong>$1</strong>');
    }

    function _relativeDate(gdtValue) {
        if (!gdtValue) { return ''; }
        var diff = GlideDateTime.subtract(new GlideDateTime(gdtValue), new GlideDateTime());
        var days = Math.abs(Math.floor(diff.getDayPart()));
        if (days === 0)  { return 'today'; }
        if (days === 1)  { return 'yesterday'; }
        if (days <= 7)   { return days + ' days ago'; }
        if (days <= 30)  { return Math.floor(days / 7) + ' weeks ago'; }
        if (days <= 365) { return Math.floor(days / 30) + ' months ago'; }
        return Math.floor(days / 365) + ' years ago';
    }

    function _generateAISummaryStub(q, results) {
        if (!results || results.length === 0) { return null; }
        var topTitles = results.slice(0, 3).map(function(r) { return '<em>' + r.title + '</em>'; }).join(', ');
        return 'Based on your search for <strong>' + q + '</strong>, the most relevant articles are: ' + topTitles + '.';
    }

})();

sp_widget.client_script:
function SearchPulseBadgeCtrl($scope) {
    'use strict';
    var c = this;
    c.badge           = $scope.data.badge           || { show: false };
    c.reputationScore = $scope.data.reputationScore || 50;
    c.trend           = $scope.data.trend           || 'stable';
    c.getIconClass = function() {
        var iconMap = { 'check-circle': 'fa-check-circle', 'refresh': 'fa-refresh', 'alert-triangle': 'fa-exclamation-triangle' };
        return iconMap[c.badge.icon] || 'fa-tag';
    };
}

sp_widget.script:
(function() {
    'use strict';

    var articleSysId = (options && options.article_sys_id) ? options.article_sys_id : null;

    if (!articleSysId && $sp) {
        var pageRecord = $sp.getRecord();
        if (pageRecord && pageRecord.getTableName() === 'kb_knowledge') {
            articleSysId = pageRecord.getUniqueValue();
        }
    }

    data.badge           = { show: false };
    data.reputationScore = 50;
    data.trend           = 'stable';

    if (!articleSysId) { return; }

    try {
        var badgeService     = new x_sp_searchpulse.SearchPulseBadgeService();
        data.badge           = badgeService.getBadge(articleSysId);
        var rankingEngine    = new x_sp_searchpulse.SearchPulseRankingEngine();
        var repInfo          = rankingEngine.getArticleReputationInfo(articleSysId);
        data.reputationScore = repInfo.score;
        data.trend           = repInfo.score_trend || 'stable';
    } catch (e) {
        gs.logError('SearchPulse badge widget error: ' + e.message, 'SearchPulse');
    }
})();
